    with closing(get_db_connection()) as conn:
        rows = conn.execute(
            "SELECT id, name, description, updated_at FROM items ORDER BY id"
        ).fetchall()
        result = [dict(row) for row in rows]

    cache_set(cache_key, result, DB_QUERY_CACHE_TTL)
    return result, False


