@app.before_request
def serve_cached_api_response():
    if request.method != "GET":
        return None

    cache_key = make_api_cache_key(request.path, request.args.to_dict(flat=True))
    cached = cache_get(cache_key)
    if cached is None:
        return None

    response = jsonify(cached["data"])
    response.status_code = cached["status"]
    for header_name, header_value in cached.get("headers", {}).items():
        response.headers[header_name] = header_value
    response.headers["X-API-Cache"] = "HIT"
    return response


@app.after_request
def store_api_response(response):
    if request.method != "GET":
        return response

    if response.status_code != 200:
        return response

    if response.content_type is None or "application/json" not in response.content_type:
        return response

    try:
        payload = json.loads(response.get_data(as_text=True))
    except Exception:
        return response

    cache_key = make_api_cache_key(request.path, request.args.to_dict(flat=True))
    headers = {
        "Content-Type": response.headers.get("Content-Type", "application/json"),
    }
    cache_set(
        cache_key,
        {"status": response.status_code, "data": payload, "headers": headers},
        API_RESPONSE_CACHE_TTL,
    )
    response.headers["X-API-Cache"] = "MISS"
    return response


